package com.pdp.mysql.project;
import com.pdp.project.domain.ProjectMember; import com.pdp.project.port.ProjectMemberRepository; import com.pdp.shared.concurrency.*; import java.time.Instant; import java.util.*; import org.springframework.stereotype.Repository;
@Repository public final class MysqlProjectMemberRepository implements ProjectMemberRepository { private final ProjectMemberMapper mapper; public MysqlProjectMemberRepository(ProjectMemberMapper mapper){this.mapper=mapper;} public List<ProjectMember> findActiveByProjectId(UUID w,UUID p,Instant at){return mapper.findActiveByProjectId(w,p,at).stream().map(ProjectMemberRow::domain).toList();} public ProjectMember insert(ProjectMember m){mapper.insert(ProjectMemberRow.from(m));return m;} public ProjectMember update(ProjectMember m,Revision e){if(mapper.update(ProjectMemberRow.from(m))==0)throw new ConcurrencyConflictException(e,e);return m;} }
